#include <vector>
#include <iostream>
#include <algorithm>
#include <stack>
using namespace std;
class Solution
{
public:
    string removeStars(string s)
    {
        stack<char> charstack;

        for (char c : s)
        {
            if (c == '*')
            {
                if (!charstack.empty())
                    charstack.pop();
            }
            else
            {
                charstack.push(c);
            }
        }

        string res = "";
        while (!charstack.empty())
        {
            res.push_back(charstack.top());
            charstack.pop();
        }

        reverse(res.begin(), res.end());
        return res;
    }
};
int main()
{
    Solution s;
    string a = "";
    cout << s.removeStars(a);
}